import type * as React from "react"

/** Identifies one cell by its TanStack row id and column id. */
export type CellPos = { rowId: string; columnId: string }

/** Direction vocabulary shared with table-fields' FieldEditContext. */
export type MoveDirection = "next" | "prev" | "up" | "down"

/** Per-column metadata stashed on ColumnDef.meta by defineColumns. */
export type DataTableColumnMeta = {
  /** Per-column editable override; undefined falls back to the table default. */
  editable?: boolean
  /** Plain-text label for UI that can't render the header function (e.g. the columns menu). */
  label: string
  /** Serializes a cell's value to clipboard/CSV text — populated from the column's FieldType.toClipboard by defineColumns. Falls back to String(value ?? "") when absent (raw ColumnDef escape-hatch columns). */
  toClipboard?: (value: unknown) => string
  /** Parses clipboard text back to a value; undefined means "couldn't parse, leave the cell alone" (paste skips it) — populated from FieldType.fromClipboard. Absent entirely (not just returning undefined) means the column can never be pasted into, e.g. a raw ColumnDef escape-hatch column with no clipboard support. */
  fromClipboard?: (text: string) => unknown
}

/** Supported footer/selection-summary aggregation methods. */
export type AggregationMethod = "sum" | "avg" | "min" | "max" | "count"

/** Dev-declared: which columns support footer aggregation and which methods. */
export type CalculableColumn = {
  columnId: string
  /** Methods offered in the picker; defaults to all five. */
  methods?: AggregationMethod[]
  /** Initial method shown before the user picks one; defaults to off (null). */
  default?: AggregationMethod | null
}

/** Args passed to the dev-supplied computeAggregate callback for scopes that exceed what's loaded client-side. */
export type ComputeAggregateArgs = {
  columnId: string
  method: AggregationMethod
  scope: "all-matching" | "selection-all-matching"
}

/**
 * Lifecycle of a server-computed aggregate value. `idle` before the user has
 * triggered a calculation; `stale` when a prior server value's inputs
 * (method or scope) have since changed but a fresh value hasn't been
 * requested yet. `partial` on a `value`/`stale` state means the number was
 * computed from loaded rows only (no `computeAggregate` was provided even
 * though the scope exceeds what's loaded) — the UI shows a qualifier rather
 * than silently presenting a wrong-looking total as authoritative.
 */
export type AggregateCellState =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "value"; value: number; partial?: boolean }
  | { status: "stale"; value: number; partial?: boolean }
  | { status: "error"; message: string }

/**
 * The live grid state + actions, provided via React Context so cell renderers
 * (built once per column by defineColumns) can read/act without prop-drilling.
 */
export type DataTableRuntime = {
  /** The single focused cell, or null before any cell has been clicked/tabbed to. */
  activeCell: CellPos | null
  /** The cell currently rendering its `edit` UI, or null when nothing is being edited. */
  editingCell: CellPos | null
  /** `pos === activeCell` — a convenience predicate so cell renderers don't do their own equality checks. */
  isActive: (pos: CellPos) => boolean
  /** `pos === editingCell` — same convenience as `isActive`, for the edit-mode branch. */
  isEditing: (pos: CellPos) => boolean
  /** Focuses a cell without entering edit mode (click, or arrow/Tab navigation). */
  setActiveCell: (pos: CellPos) => void
  /** Enters edit mode for `pos`; a no-op if `isColumnEditable(pos.columnId)` is false. */
  beginEdit: (pos: CellPos) => void
  /** Exits edit mode (on commit or cancel) without changing `activeCell`. */
  stopEditing: () => void
  /**
   * Moves `activeCell` one step in the given direction and exits edit mode.
   * "next"/"prev" move horizontally and wrap to the next/previous row at a row
   * edge; "up"/"down" move vertically and clamp (do not wrap) at the grid edge.
   */
  moveActive: (dir: MoveDirection) => void
  /** Resolves the column's `DataTableColumnMeta.editable` override against the table-level default (set in useDataTable). */
  isColumnEditable: (columnId: string) => boolean
  /** Reports an intended cell edit. The raw, field-supplied value — callers own coercion/validation; the library never mutates `data` itself. */
  updateData: (rowId: string, columnId: string, value: unknown) => void
  /** Wired once on the grid's root element (not per-cell) to drive arrow-key/Tab/Enter navigation of the active cell. */
  handleKeyDown: (e: React.KeyboardEvent) => void
  /** Whether pagination is server-driven (useDataTable's manualPagination option) — lets cell renderers (row-gutter, footer) tell whether more rows exist beyond what's loaded. */
  manualPagination: boolean
  /** Total row count across all pages when manualPagination is true; undefined for client-side pagination, where loaded rows already are all rows. */
  totalRowCount: number | undefined
  /**
   * True once the user's select-all click cycle has advanced past "every
   * loaded/filtered row" to "every row matching the current filter,
   * including any not yet loaded" — a logical selection, not a
   * materialization of every id. Only meaningful when `totalRowCount`
   * exceeds the loaded row count; otherwise selecting every loaded row
   * already means "everything," and this stays false.
   */
  isAllMatchingSelected: boolean
  /**
   * Sets `isAllMatchingSelected`. Turning it on also selects every
   * currently-loaded row (via the table's own row-selection state) so the
   * visible checkboxes agree with the logical "everything" state; turning
   * it off does NOT automatically deselect loaded rows, since the caller
   * may be narrowing from "all-matching" back to "all loaded" rather than
   * to "none" — the row-gutter's click-cycle (a later task) owns that
   * distinction and calls the appropriate table method itself when needed.
   */
  setAllMatchingSelected: (matching: boolean) => void
  /**
   * Selects/deselects a single row by id. When `shiftKey` is true and a
   * prior call has recorded an anchor row, every row between the anchor and
   * `rowId` (inclusive, resolved by their live position in the current row
   * model) is set to `checked` instead of toggling just the one row —
   * Sheets/Gmail-style range select. Always updates the anchor to `rowId`
   * afterward, shift-click or not. Takes an id rather than a positional
   * index deliberately: TanStack's `Row.index` is fixed at row creation to
   * the row's position in the original, unsorted data, not its current
   * on-screen position, so an index captured at click time can point at the
   * wrong row (or nothing) once sorting/filtering has reordered the table.
   */
  toggleRowSelected: (rowId: string, checked: boolean, shiftKey: boolean) => void
  /** Re-issues updateData with the most recent edit's PRIOR value(s) — a no-op if there's nothing to undo. Also used internally to undo a paste or bulk-clear batch as one step. */
  undo: () => void
  /** Re-applies the most recently undone edit's NEW value(s) — a no-op if there's nothing to redo. */
  redo: () => void
  /** Whether `undo()` currently does anything — for a consumer building custom undo UI; the shipped grid itself only exposes undo/redo via Cmd/Ctrl+Z keyboard shortcuts. */
  canUndo: boolean
  /** Whether `redo()` currently does anything. */
  canRedo: boolean
}

export type FilterType = "text" | "number" | "select" | "date"

export type FilterOperator =
  | "contains" | "doesNotContain" | "equals" | "isNot" | "startsWith"
  | "eq" | "ne" | "gt" | "lt" | "between"
  | "is" | "isAnyOf" | "isNoneOf"
  | "before" | "after" | "dateBetween"

export type FilterDef = {
  /**
   * Must match a column's `id`/`accessorKey` AND a key on the row data — the
   * filter engine reads the value via `row[id]`. Filterable columns must
   * therefore be accessorKey-based (not `accessorFn`-only).
   */
  id: string
  label: string
  type: FilterType
  /** Allowed operators; falls back to the type default when omitted. */
  operators?: FilterOperator[]
  /** Required for type "select" — the choosable values. */
  options?: { label: string; value: string }[]
}

export type FilterValue =
  | string
  | number
  | [number, number]
  | [string, string]
  | string[]
  | null

export type FilterCondition = {
  /** Unique id for keying / removal. */
  id: string
  columnId: string
  operator: FilterOperator
  value: FilterValue
}

export type Combinator = "and" | "or"
export type FilterGroup = { id: string; combinator: Combinator; conditions: FilterCondition[] }
export type FilterState = { combinator: Combinator; groups: FilterGroup[] }

/** One developer-configured entry in the Actions dropdown. */
export type DataTableAction<TData> = {
  /** Unique id for keying. */
  id: string
  label: string
  icon?: React.ComponentType<{ className?: string }>
  /** Disable this action (e.g. based on selection state); defaults to enabled. */
  disabled?: boolean
  variant?: "default" | "destructive"
  /**
   * `rowIds`/`rows` are the selected rows that exist client-side. When
   * `allMatching` is true (manual pagination, the select-all cycle advanced
   * to "every row matching the filter"), the logical selection exceeds what's
   * loaded — `rows` covers only the loaded subset, and the action should run
   * its own server-side bulk path (mirroring how `computeAggregate` handles
   * the same scope for footer aggregation) rather than iterating `rows`.
   */
  onClick: (context: { rowIds: string[]; rows: TData[]; allMatching: boolean }) => void
}

import type { AggregationMethod } from "./types"

/**
 * Pure aggregation over numeric values, shared by the footer's client-side
 * scope and (by convention — the dev's own `computeAggregate` implementation
 * is expected to mirror this) the server path.
 *
 * `count` counts every value regardless of blankness (matches "row count"
 * semantics); sum/avg/min/max ignore null/undefined/NaN entries so a blank
 * cell doesn't corrupt the result. An all-blank/empty input returns 0 for
 * sum (the additive identity) and NaN for avg/min/max, since there's no
 * meaningful average/min/max of nothing — callers format NaN as an em dash
 * rather than the literal string "NaN".
 */
export function aggregate(
  method: AggregationMethod,
  values: (number | null | undefined)[],
): number {
  if (method === "count") return values.length

  // typeof check matters: Number.isNaN alone lets non-number values (e.g. a
  // string, when calculableColumns points at a text column) slip through the
  // type predicate untouched — and `0 + "abc"` concatenates instead of adding.
  const nums = values.filter((v): v is number => typeof v === "number" && !Number.isNaN(v))
  switch (method) {
    case "sum":
      return nums.reduce((a, b) => a + b, 0)
    case "avg":
      return nums.length === 0 ? Number.NaN : nums.reduce((a, b) => a + b, 0) / nums.length
    case "min":
      return nums.length === 0 ? Number.NaN : Math.min(...nums)
    case "max":
      return nums.length === 0 ? Number.NaN : Math.max(...nums)
  }
}

/** Human-readable labels for the method picker UI. */
export const AGGREGATION_METHOD_LABELS: Record<AggregationMethod, string> = {
  sum: "Sum",
  avg: "Average",
  min: "Min",
  max: "Max",
  count: "Count",
}

/** Ordered list of all methods, for the picker's option list. */
export const ALL_AGGREGATION_METHODS: AggregationMethod[] = ["sum", "avg", "min", "max", "count"]

/** One cell's before/after value, as reported to the undo stack at the moment it changed. */
export type CellEdit = { rowId: string; columnId: string; prev: unknown; next: unknown }

/**
 * One or more CellEdits that undo/redo together atomically — a single edit
 * is a one-element batch; a paste or bulk-clear is a multi-element batch, so
 * one Ctrl+Z undoes the whole operation, not one cell at a time.
 */
export type UndoBatch = CellEdit[]

export type UndoStack = {
  /** Records a batch as the next undoable step. A new push always clears any pending redo — see the "branching history" test above. Empty batches are ignored. */
  push: (batch: UndoBatch) => void
  /** Pops and returns the most recent batch (the caller applies each edit's `prev`), or null if there's nothing to undo. */
  undo: () => UndoBatch | null
  /** Pops and returns the most recently undone batch (the caller applies each edit's `next`), or null if there's nothing to redo. */
  redo: () => UndoBatch | null
  canUndo: () => boolean
  canRedo: () => boolean
  /** Empties both stacks — not currently called by use-data-table.ts, but exposed for a future "data prop changed out from under us" reset, mirroring the isAllMatchingSelected reconciliation added in Plan 3. */
  clear: () => void
}

/**
 * Plain, React-free history stack. `maxSize` bounds memory on a long editing
 * session — the oldest batch is silently dropped once the cap is exceeded,
 * same convention as most spreadsheet undo stacks (no error, no toast; a
 * user editing 100+ cells in one session and going back further than that
 * is an extreme edge case, not a correctness concern worth surfacing).
 */
export function createUndoStack(maxSize = 100): UndoStack {
  let past: UndoBatch[] = []
  let future: UndoBatch[] = []

  return {
    push(batch) {
      if (batch.length === 0) return
      past.push(batch)
      if (past.length > maxSize) past.shift()
      future = []
    },
    undo() {
      const batch = past.pop()
      if (!batch) return null
      future.push(batch)
      return batch
    },
    redo() {
      const batch = future.pop()
      if (!batch) return null
      past.push(batch)
      return batch
    },
    canUndo: () => past.length > 0,
    canRedo: () => future.length > 0,
    clear() {
      past = []
      future = []
    },
  }
}

/** A column's clipboard serialize/parse pair, as read off DataTableColumnMeta by the React-level copy/paste glue in use-data-table.ts. */
export type ClipboardColumn = {
  id: string
  toClipboard: (value: unknown) => string
  /** Absent (not just returning undefined) means this column can never be pasted into. */
  fromClipboard?: (text: string) => unknown
}

/**
 * Parses TSV text (as read from the clipboard) into a 2D grid of raw cell
 * strings. Normalizes \r\n and bare \r line endings to \n before parsing.
 * Quote-aware, matching what Excel/Sheets actually emit: a cell containing a
 * literal tab, newline, or quote is wrapped in double quotes (with embedded
 * quotes doubled), so a copied multi-line cell must land in ONE grid cell
 * rather than being naively split into phantom rows/columns. A quote only
 * opens quoted mode at the start of a field; mid-field quotes are literal
 * (also matching spreadsheet behavior). Drops exactly one trailing empty
 * line — pasting from Excel/Sheets always ends the copied block with a line
 * terminator, which would otherwise show up as one extra, entirely-empty row.
 */
export function parseTsv(text: string): string[][] {
  const normalized = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n")
  const rows: string[][] = [[]]
  let field = ""
  let fieldStarted = false // distinguishes "" (empty so far) from content beginning with a literal quote
  let inQuotes = false
  let i = 0
  while (i < normalized.length) {
    const ch = normalized[i]
    if (inQuotes) {
      if (ch === '"') {
        if (normalized[i + 1] === '"') {
          field += '"'
          i += 2
          continue
        }
        inQuotes = false
        i++
        continue
      }
      field += ch
      i++
      continue
    }
    if (ch === '"' && !fieldStarted && field === "") {
      inQuotes = true
      fieldStarted = true
      i++
      continue
    }
    if (ch === "\t") {
      rows[rows.length - 1].push(field)
      field = ""
      fieldStarted = false
      i++
      continue
    }
    if (ch === "\n") {
      rows[rows.length - 1].push(field)
      rows.push([])
      field = ""
      fieldStarted = false
      i++
      continue
    }
    field += ch
    fieldStarted = true
    i++
  }
  rows[rows.length - 1].push(field)
  const last = rows[rows.length - 1]
  if (rows.length > 1 && last.length === 1 && last[0] === "") rows.pop()
  return rows
}

/** Quote-wraps a TSV field when it contains a tab, newline, or quote (doubling embedded quotes), as Excel/Sheets do — so a multi-line longText cell survives a copy→paste round-trip intact. */
function encodeTsvField(text: string): string {
  return /[\t\n\r"]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text
}

/**
 * Serializes a rectangular grid of raw values into Excel/Sheets-pasteable
 * TSV, running each value through its column's toClipboard. `columns` must
 * be in the same left-to-right order as `grid`'s inner arrays.
 */
export function gridToTsv(grid: unknown[][], columns: ClipboardColumn[]): string {
  return grid
    .map((row) =>
      row.map((value, i) => encodeTsvField(columns[i]?.toClipboard(value) ?? "")).join("\t"),
    )
    .join("\n")
}

export type PastePlan<TData> = {
  /** Writes to existing rows — hand to DataTableRuntime's internal commitBatch. */
  updates: { rowId: string; columnId: string; value: unknown }[]
  /** Rows the pasted block extends past the last existing row — hand to onCreateRows. */
  newRows: Partial<TData>[]
}

/**
 * Maps a parsed TSV grid onto the table starting at (startRowIndex,
 * startColIndex) in on-screen row/column order. A cell is skipped (neither
 * an update nor part of a new row) when its target column has no
 * fromClipboard at all, or when fromClipboard returns undefined for that
 * cell's text (unparseable) — "skip, don't apply" matches the read-only
 * gate's existing "cells stay copyable but never edit-affected when not
 * editable" principle, applied per-cell across the pasted block.
 */
export function planPaste<TData>(
  parsedGrid: string[][],
  startRowIndex: number,
  startColIndex: number,
  rowIds: string[],
  columns: ClipboardColumn[],
): PastePlan<TData> {
  const updates: PastePlan<TData>["updates"] = []
  const newRows: Partial<TData>[] = []

  parsedGrid.forEach((line, rOffset) => {
    const rowIndex = startRowIndex + rOffset
    const rowId: string | undefined = rowIds[rowIndex]
    const partial: Record<string, unknown> = {}
    let hasAny = false

    line.forEach((cellText, cOffset) => {
      const column = columns[startColIndex + cOffset]
      if (!column?.fromClipboard) return
      const value = column.fromClipboard(cellText)
      if (value === undefined) return
      if (rowId) {
        updates.push({ rowId, columnId: column.id, value })
      } else {
        partial[column.id] = value
        hasAny = true
      }
    })

    if (!rowId && hasAny) newRows.push(partial as Partial<TData>)
  })

  return { updates, newRows }
}

/** A column's export label + serializer, as read off DataTableColumnMeta by the React-level export glue in data-table.tsx. */
export type CsvColumn = { id: string; label: string; toClipboard: (value: unknown) => string }

// CSV/Excel formula injection (CWE-1236): a field starting with =, +, -, or
// @ is executed as a formula by Excel/Sheets/LibreOffice on open, not shown
// as plain text — a real risk for a feature whose whole purpose is producing
// a file the user opens in a spreadsheet app. Prefixing with a single quote
// is the standard OWASP-documented mitigation: spreadsheet apps treat a
// leading `'` as "force text," so the cell displays literally instead of
// evaluating, while non-spreadsheet CSV consumers (this module's own
// `exportCsv` tests, any other parser) just see the extra leading character
// as part of the field's plain text. Checked BEFORE quote-escaping below,
// since the prefix itself never contains a comma/quote/newline and so never
// needs quoting on its own account.
function neutralizeFormulaPrefix(field: string): string {
  return /^[=+\-@]/.test(field) ? `'${field}` : field
}

// RFC 4180: quote a field if it contains the delimiter, a quote, or a line
// break; a literal quote inside a quoted field is escaped by doubling it.
function escapeCsvField(field: string): string {
  const safe = neutralizeFormulaPrefix(field)
  if (/[",\n\r]/.test(safe)) return `"${safe.replace(/"/g, '""')}"`
  return safe
}

/**
 * Builds a CSV string (CRLF line endings, RFC 4180 quoting) from plain
 * row-value records, running each value through its column's toClipboard —
 * the same formatting copy/paste uses, so an exported number/currency/date
 * cell reads the same as what a user would see if they copied it.
 */
export function exportCsv(rows: Record<string, unknown>[], columns: CsvColumn[]): string {
  const header = columns.map((c) => escapeCsvField(c.label))
  const body = rows.map((row) => columns.map((c) => escapeCsvField(c.toClipboard(row[c.id]))))
  return [header, ...body].map((line) => line.join(",")).join("\r\n")
}

/**
 * Triggers a browser file download of `csv` as `filename` via a throwaway
 * object URL + anchor click. Pure DOM plumbing, not unit-tested the same way
 * as exportCsv above (jsdom has no real download pipeline to assert
 * against) — verified in a later task's manual browser check instead.
 */
export function downloadCsv(filename: string, csv: string): void {
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" })
  const url = URL.createObjectURL(blob)
  const a = document.createElement("a")
  a.href = url
  a.download = filename
  a.click()
  URL.revokeObjectURL(url)
}

import type {
  Combinator,
  FilterCondition,
  FilterDef,
  FilterGroup,
  FilterOperator,
  FilterState,
  FilterType,
  FilterValue,
} from "./types"

const DEFAULT_OPERATORS: Record<FilterType, FilterOperator[]> = {
  text: ["contains", "doesNotContain", "equals", "isNot", "startsWith"],
  number: ["eq", "ne", "gt", "lt", "between"],
  select: ["isAnyOf", "isNoneOf", "is"],
  date: ["before", "after", "dateBetween"],
}

export const OPERATOR_LABELS: Record<FilterOperator, string> = {
  contains: "contains",
  doesNotContain: "does not contain",
  equals: "is",
  isNot: "is not",
  startsWith: "starts with",
  eq: "equals",
  ne: "not equal",
  gt: "greater than",
  lt: "less than",
  between: "between",
  is: "is",
  isAnyOf: "is any of",
  isNoneOf: "is none of",
  before: "before",
  after: "after",
  dateBetween: "between",
}

export function defaultOperatorsFor(type: FilterType): FilterOperator[] {
  return DEFAULT_OPERATORS[type]
}

export function operatorsForDef(def: FilterDef): FilterOperator[] {
  return def.operators && def.operators.length > 0
    ? def.operators
    : defaultOperatorsFor(def.type)
}

function isEmpty(value: FilterValue): boolean {
  if (value == null) return true
  if (typeof value === "string") return value.trim() === ""
  if (Array.isArray(value)) {
    return value.length === 0 || value.every((v) => v == null || v === "")
  }
  return false
}

export function evaluateCondition(
  cellValue: unknown,
  operator: FilterOperator,
  value: FilterValue,
): boolean {
  if (isEmpty(value)) return true

  const text = String(cellValue ?? "").toLowerCase()
  switch (operator) {
    case "contains":
      return text.includes(String(value).toLowerCase())
    case "equals":
      return text === String(value).toLowerCase()
    case "startsWith":
      return text.startsWith(String(value).toLowerCase())
    case "eq":
      return Number(cellValue) === Number(value)
    case "ne":
      return Number(cellValue) !== Number(value)
    case "gt":
      return Number(cellValue) > Number(value)
    case "lt":
      return Number(cellValue) < Number(value)
    case "between": {
      // Guard: range operators need a [min, max] pair; a scalar mid-build
      // (e.g. only one bound entered) is treated as no constraint, not a crash.
      if (!Array.isArray(value)) return true
      const [min, max] = value as [number, number]
      // Either bound still blank (mid-build) → no constraint, so the table
      // doesn't go empty while the user is typing the first bound.
      if (String(min).trim() === "" || String(max).trim() === "") return true
      const n = Number(cellValue)
      return n >= Number(min) && n <= Number(max)
    }
    case "doesNotContain":
      return !text.includes(String(value).toLowerCase())
    case "isNot":
      return String(cellValue ?? "").toLowerCase() !== String(value).toLowerCase()
    case "isNoneOf":
      return !(value as string[]).map(String).includes(String(cellValue ?? ""))
    // `is`/`isAnyOf`/`isNoneOf` are case-sensitive by design: select columns hold
    // exact enum values (e.g. "HSBC"), unlike the case-insensitive text operators.
    case "is":
      return String(cellValue ?? "") === String(value)
    case "isAnyOf":
      return (value as string[]).map(String).includes(String(cellValue ?? ""))
    case "before":
      return new Date(String(cellValue)).getTime() < new Date(String(value)).getTime()
    case "after":
      return new Date(String(cellValue)).getTime() > new Date(String(value)).getTime()
    case "dateBetween": {
      if (!Array.isArray(value)) return true
      const [start, end] = value as string[]
      if (String(start).trim() === "" || String(end).trim() === "") return true
      const t = new Date(String(cellValue)).getTime()
      return t >= new Date(start).getTime() && t <= new Date(end).getTime()
    }
    default:
      return true
  }
}

export function describeCondition(
  condition: FilterCondition,
  def?: FilterDef,
): string {
  const label = def?.label ?? condition.columnId
  const op = OPERATOR_LABELS[condition.operator]
  const value = condition.value

  const labelFor = (raw: unknown): string =>
    def?.type === "select"
      ? (def.options?.find((o) => o.value === String(raw))?.label ?? String(raw))
      : String(raw)

  let valueStr: string
  if (Array.isArray(value)) {
    const sep =
      condition.operator === "between" || condition.operator === "dateBetween"
        ? "–"
        : ", "
    valueStr = value.map(labelFor).join(sep)
  } else if (value == null) {
    valueStr = ""
  } else {
    valueStr = labelFor(value)
  }
  return `${label} ${op} ${valueStr}`.trim()
}

export function createCondition(
  filterDefs: FilterDef[],
  id: string,
): FilterCondition {
  const def = filterDefs[0]
  if (!def) {
    throw new Error("createCondition: filterDefs must not be empty")
  }
  return { id, columnId: def.id, operator: operatorsForDef(def)[0], value: null }
}

export function withColumn(
  condition: FilterCondition,
  columnId: string,
  filterDefs: FilterDef[],
): FilterCondition {
  const def = filterDefs.find((d) => d.id === columnId) ?? filterDefs[0]
  return {
    ...condition,
    columnId: def.id,
    operator: operatorsForDef(def)[0],
    value: null,
  }
}

export function withOperator(
  condition: FilterCondition,
  operator: FilterOperator,
): FilterCondition {
  return { ...condition, operator, value: null }
}

export function withValue(
  condition: FilterCondition,
  value: FilterValue,
): FilterCondition {
  return { ...condition, value }
}

// ─── Filter v2: group model + tree evaluation ────────────────────────────────

export function isConditionComplete(condition: FilterCondition): boolean {
  return !isEmpty(condition.value)
}

export function evaluateGroup(group: FilterGroup, get: (columnId: string) => unknown): boolean {
  const active = group.conditions.filter(isConditionComplete)
  if (active.length === 0) return true
  const results = active.map((c) => evaluateCondition(get(c.columnId), c.operator, c.value))
  return group.combinator === "and" ? results.every(Boolean) : results.some(Boolean)
}

export function evaluateFilterState(state: FilterState, get: (columnId: string) => unknown): boolean {
  const active = state.groups.filter((g) => g.conditions.some(isConditionComplete))
  if (active.length === 0) return true
  const results = active.map((g) => evaluateGroup(g, get))
  return state.combinator === "and" ? results.every(Boolean) : results.some(Boolean)
}

export function countActiveConditions(state: FilterState): number {
  return state.groups.reduce((sum, g) => sum + g.conditions.filter(isConditionComplete).length, 0)
}

export function emptyFilterState(): FilterState {
  return { combinator: "and", groups: [] }
}

export function newGroup(id: string, conditionId: string, filterDefs: FilterDef[]): FilterGroup {
  return { id, combinator: "and", conditions: [createCondition(filterDefs, conditionId)] }
}

export function addGroup(state: FilterState, groupId: string, conditionId: string, filterDefs: FilterDef[]): FilterState {
  return { ...state, groups: [...state.groups, newGroup(groupId, conditionId, filterDefs)] }
}

function mapGroup(state: FilterState, groupId: string, fn: (g: FilterGroup) => FilterGroup): FilterState {
  return { ...state, groups: state.groups.map((g) => (g.id === groupId ? fn(g) : g)) }
}

export function addConditionToGroup(state: FilterState, groupId: string, condition: FilterCondition): FilterState {
  return mapGroup(state, groupId, (g) => ({ ...g, conditions: [...g.conditions, condition] }))
}

export function updateConditionInGroup(state: FilterState, groupId: string, condition: FilterCondition): FilterState {
  return mapGroup(state, groupId, (g) => ({ ...g, conditions: g.conditions.map((c) => (c.id === condition.id ? condition : c)) }))
}

/**
 * Removes a single condition from a group. If the group becomes empty it is
 * dropped from the state entirely. Use `removeGroup` to remove a group explicitly
 * regardless of its condition count.
 */
export function removeConditionFromGroup(state: FilterState, groupId: string, conditionId: string): FilterState {
  const next = mapGroup(state, groupId, (g) => ({ ...g, conditions: g.conditions.filter((c) => c.id !== conditionId) }))
  return { ...next, groups: next.groups.filter((g) => g.conditions.length > 0) }
}

export function removeGroup(state: FilterState, groupId: string): FilterState {
  return { ...state, groups: state.groups.filter((g) => g.id !== groupId) }
}

export function setGroupCombinator(state: FilterState, groupId: string, combinator: Combinator): FilterState {
  return mapGroup(state, groupId, (g) => ({ ...g, combinator }))
}

export function setTopCombinator(state: FilterState, combinator: Combinator): FilterState {
  return { ...state, combinator }
}

export function normalizeFilterState(state: FilterState, filterableIds: string[]): FilterState {
  const allowed = new Set(filterableIds)
  const groups = state.groups
    .map((g) => ({ ...g, conditions: g.conditions.filter((c) => allowed.has(c.columnId)) }))
    .filter((g) => g.conditions.length > 0)
  return { ...state, groups }
}

"use client"

import * as React from "react"

import type { CellPos, MoveDirection } from "./types"

export type UseGridNavigationOptions = {
  rowIds: string[]
  columnIds: string[]
  isColumnEditable: (columnId: string) => boolean
}

export type GridNavigation = {
  activeCell: CellPos | null
  editingCell: CellPos | null
  isActive: (pos: CellPos) => boolean
  isEditing: (pos: CellPos) => boolean
  setActiveCell: (pos: CellPos) => void
  beginEdit: (pos: CellPos) => void
  stopEditing: () => void
  moveActive: (dir: MoveDirection) => void
  handleKeyDown: (e: React.KeyboardEvent) => void
}

function samePos(a: CellPos | null, b: CellPos): boolean {
  return a != null && a.rowId === b.rowId && a.columnId === b.columnId
}

/**
 * Pure grid navigation: active/editing cell state + keyboard handling, over
 * plain row/column id lists. No TanStack Table dependency — testable with
 * fabricated ids. `use-data-table.ts` supplies the real ids and combines this
 * with column-editability and data persistence into the full DataTableRuntime.
 *
 * Two responsibilities that belong to `use-data-table.ts`, not here:
 * 1. Memoize `rowIds`/`columnIds` (e.g. `useMemo` over `table.getRowModel().rows`).
 *    `moveActive`/`handleKeyDown` depend on both arrays by reference, so a
 *    fresh array every render defeats memoization on every consumer.
 * 2. Revalidate `activeCell` when the id lists change under it (sort/filter/
 *    delete) — see the comment on the orphaned-id guard in `moveActive` below.
 */
export function useGridNavigation({
  rowIds,
  columnIds,
  isColumnEditable,
}: UseGridNavigationOptions): GridNavigation {
  const [activeCell, setActiveCellState] = React.useState<CellPos | null>(null)
  const [editingCell, setEditingCell] = React.useState<CellPos | null>(null)

  const setActiveCell = React.useCallback((pos: CellPos) => {
    // Focusing a different cell always exits whatever was being edited — a
    // click elsewhere is an implicit "stop editing", not a silent orphan of
    // editingCell (which would otherwise still be "editing" a cell that's no
    // longer active, while the newly active cell shows no editor).
    setEditingCell(null)
    setActiveCellState(pos)
  }, [])

  const beginEdit = React.useCallback(
    (pos: CellPos) => {
      if (!isColumnEditable(pos.columnId)) return
      setActiveCellState(pos)
      setEditingCell(pos)
    },
    [isColumnEditable],
  )

  const stopEditing = React.useCallback(() => {
    setEditingCell(null)
  }, [])

  const moveActive = React.useCallback(
    (dir: MoveDirection) => {
      setEditingCell(null)
      setActiveCellState((current) => {
        if (rowIds.length === 0 || columnIds.length === 0) return current
        if (!current) return { rowId: rowIds[0], columnId: columnIds[0] }

        const rowIdx = rowIds.indexOf(current.rowId)
        const colIdx = columnIds.indexOf(current.columnId)
        // `current` points at a row/column id no longer in the live lists —
        // e.g. a sort/filter/delete on the table removed it while it was
        // active. This hook is deliberately table-agnostic (see the module
        // doc comment) and has no principled way to pick a replacement
        // position, so it holds still rather than guessing. The owner of
        // `rowIds`/`columnIds` (use-data-table.ts) is responsible for
        // resetting or revalidating `activeCell` — e.g. via setActiveCell —
        // when the id lists it derives from the table change out from under
        // an active cell; a silently-frozen active cell is otherwise a real
        // dead end for keyboard navigation.
        if (rowIdx === -1 || colIdx === -1) return current

        if (dir === "up") {
          return { rowId: rowIds[Math.max(0, rowIdx - 1)], columnId: current.columnId }
        }
        if (dir === "down") {
          return {
            rowId: rowIds[Math.min(rowIds.length - 1, rowIdx + 1)],
            columnId: current.columnId,
          }
        }
        if (dir === "prev") {
          if (colIdx > 0) return { rowId: current.rowId, columnId: columnIds[colIdx - 1] }
          if (rowIdx > 0) {
            return { rowId: rowIds[rowIdx - 1], columnId: columnIds[columnIds.length - 1] }
          }
          return current
        }
        // "next"
        if (colIdx < columnIds.length - 1) {
          return { rowId: current.rowId, columnId: columnIds[colIdx + 1] }
        }
        if (rowIdx < rowIds.length - 1) {
          return { rowId: rowIds[rowIdx + 1], columnId: columnIds[0] }
        }
        return current
      })
    },
    [rowIds, columnIds],
  )

  const handleKeyDown = React.useCallback(
    (e: React.KeyboardEvent) => {
      if (editingCell) {
        if (e.key === "Escape") {
          stopEditing()
          e.preventDefault()
        }
        return
      }
      if (!activeCell) return
      switch (e.key) {
        case "ArrowUp":
          moveActive("up")
          e.preventDefault()
          break
        case "ArrowDown":
          moveActive("down")
          e.preventDefault()
          break
        case "ArrowLeft":
          moveActive("prev")
          e.preventDefault()
          break
        case "ArrowRight":
          moveActive("next")
          e.preventDefault()
          break
        case "Tab":
          moveActive(e.shiftKey ? "prev" : "next")
          e.preventDefault()
          break
        case "Enter":
          beginEdit(activeCell)
          e.preventDefault()
          break
        default:
          break
      }
    },
    [activeCell, editingCell, moveActive, beginEdit, stopEditing],
  )

  return {
    activeCell,
    editingCell,
    isActive: (pos) => samePos(activeCell, pos),
    isEditing: (pos) => samePos(editingCell, pos),
    setActiveCell,
    beginEdit,
    stopEditing,
    moveActive,
    handleKeyDown,
  }
}

"use client"

import * as React from "react"
import type { Table } from "@tanstack/react-table"

import { aggregate } from "./aggregate"
import type {
  AggregateCellState,
  AggregationMethod,
  CalculableColumn,
  ComputeAggregateArgs,
} from "./types"

export type UseFooterAggregationOptions<TData> = {
  table: Table<TData>
  calculableColumns?: CalculableColumn[]
  computeAggregate?: (args: ComputeAggregateArgs) => Promise<number>
  manualPagination?: boolean
  totalRowCount?: number
  isAllMatchingSelected: boolean
}

export type FooterAggregationResult = {
  /** Live method per calculable column; null means "off" (no footer value shown). */
  methods: Record<string, AggregationMethod | null>
  setMethod: (columnId: string, method: AggregationMethod | null) => void
  /** Resolved display state for a column's current method, or undefined if the column isn't calculable or its method is off. */
  stateFor: (columnId: string) => AggregateCellState | undefined
  /** True when the footer is summarizing a selection rather than all visible rows. */
  scopeIsSelection: boolean
  /** Re-requests a server value for a column currently showing a "Calculate" trigger (idle) or a stale value. */
  calculate: (columnId: string) => void
}

export function useFooterAggregation<TData>({
  table,
  calculableColumns = [],
  computeAggregate,
  manualPagination = false,
  totalRowCount,
  isAllMatchingSelected,
}: UseFooterAggregationOptions<TData>): FooterAggregationResult {
  const columnConfig = React.useMemo(() => {
    const map = new Map<string, CalculableColumn>()
    for (const c of calculableColumns) map.set(c.columnId, c)
    return map
  }, [calculableColumns])

  const [methods, setMethods] = React.useState<Record<string, AggregationMethod | null>>(() => {
    const initial: Record<string, AggregationMethod | null> = {}
    for (const c of calculableColumns) initial[c.columnId] = c.default ?? null
    return initial
  })

  const setMethod = React.useCallback((columnId: string, method: AggregationMethod | null) => {
    setMethods((prev) => ({ ...prev, [columnId]: method }))
  }, [])

  const selectedRows = table.getSelectedRowModel().rows
  const scopeIsSelection = isAllMatchingSelected || selectedRows.length > 0
  const scopeRows = scopeIsSelection ? selectedRows : table.getSortedRowModel().rows

  const loadedRowCount = table.getSortedRowModel().rows.length
  // Only the all-matching selection can ever exceed what's loaded — a
  // hand-picked selection of specific rows is, by definition, a selection of
  // rows the user could see (and therefore rows already loaded).
  const scopeExceedsLoaded =
    manualPagination &&
    totalRowCount !== undefined &&
    (scopeIsSelection ? isAllMatchingSelected : totalRowCount > loadedRowCount)

  const [serverStates, setServerStates] = React.useState<Record<string, AggregateCellState>>({})

  // If the user changes method/scope and re-triggers calculate() before an
  // earlier in-flight request for the same column has resolved, the two
  // promises race: whichever settles last would otherwise win, even if it's
  // the stale one. Each calculate() call bumps a per-column request id, and
  // its .then/.catch only commits state if that id is still the latest one
  // recorded for the column when the promise settles — otherwise a newer
  // request has already superseded it and the result is silently dropped.
  const requestIdRef = React.useRef<Record<string, number>>({})

  const calculate = React.useCallback(
    (columnId: string) => {
      const method = methods[columnId]
      if (!method || !computeAggregate) return
      const requestId = (requestIdRef.current[columnId] ?? 0) + 1
      requestIdRef.current[columnId] = requestId
      setServerStates((prev) => ({ ...prev, [columnId]: { status: "loading" } }))
      computeAggregate({
        columnId,
        method,
        scope: scopeIsSelection ? "selection-all-matching" : "all-matching",
      })
        .then((value) => {
          if (requestIdRef.current[columnId] !== requestId) return // superseded by a newer request
          setServerStates((prev) => ({ ...prev, [columnId]: { status: "value", value } }))
        })
        .catch((err: unknown) => {
          if (requestIdRef.current[columnId] !== requestId) return // superseded by a newer request
          const message = err instanceof Error ? err.message : "Failed to calculate"
          setServerStates((prev) => ({ ...prev, [columnId]: { status: "error", message } }))
        })
    },
    [methods, computeAggregate, scopeIsSelection],
  )

  // A resolved server value goes stale when its inputs (method or scope)
  // change since it was last requested — re-derive an identity key per
  // column each render and compare against what was last seen. The same key
  // change also has to invalidate a request still in flight: bumping the
  // column's request id makes the pending promise's commit guard fail on
  // arrival, so a "sum" requested before the user switched to "avg" can never
  // land and display under the new method's label as if it were fresh. A
  // column caught mid-flight resets to idle (its "Calculate" trigger) rather
  // than staying loading forever for a result that will now be dropped.
  const requestKeyRef = React.useRef<Record<string, string>>({})
  React.useEffect(() => {
    for (const columnId of columnConfig.keys()) {
      const method = methods[columnId]
      const key = `${method ?? ""}:${scopeIsSelection ? "selection" : "all"}`
      const prevKey = requestKeyRef.current[columnId]
      if (prevKey !== undefined && prevKey !== key) {
        requestIdRef.current[columnId] = (requestIdRef.current[columnId] ?? 0) + 1
        setServerStates((prev) => {
          const existing = prev[columnId]
          if (existing?.status === "value") {
            return { ...prev, [columnId]: { status: "stale", value: existing.value } }
          }
          if (existing?.status === "loading") {
            return { ...prev, [columnId]: { status: "idle" } }
          }
          return prev
        })
      }
      requestKeyRef.current[columnId] = key
    }
  }, [methods, scopeIsSelection, columnConfig])

  const stateFor = React.useCallback(
    (columnId: string): AggregateCellState | undefined => {
      const method = methods[columnId]
      if (!columnConfig.has(columnId) || !method) return undefined

      if (scopeExceedsLoaded && computeAggregate) {
        return serverStates[columnId] ?? { status: "idle" }
      }

      const values = scopeRows.map((row) => row.getValue(columnId) as number | null | undefined)
      const value = aggregate(method, values)
      return scopeExceedsLoaded
        ? { status: "value", value, partial: true }
        : { status: "value", value }
    },
    [methods, columnConfig, scopeExceedsLoaded, computeAggregate, serverStates, scopeRows],
  )

  return { methods, setMethod, stateFor, scopeIsSelection, calculate }
}

"use client"

import * as React from "react"

import type { DataTableRuntime } from "./types"

/**
 * Carries the live DataTableRuntime (active/editing cell, navigation,
 * updateData) to cell renderers built by defineColumns, without prop-drilling
 * through every ColumnDef. Null outside a <DataTable> (or when a column
 * built with defineColumns is rendered in a plain table — see define-columns.ts's
 * fallback-to-display behavior in that case).
 */
export const DataTableRuntimeContext = React.createContext<DataTableRuntime | null>(null)

export function useDataTableRuntime(): DataTableRuntime | null {
  return React.useContext(DataTableRuntimeContext)
}

"use client"

import * as React from "react"
import type { CellContext, ColumnDef } from "@tanstack/react-table"

import {
  buttonField,
  checkboxField,
  currencyField,
  dateField,
  durationField,
  emailField,
  longTextField,
  multiSelectField,
  numberField,
  percentField,
  phoneField,
  ratingField,
  singleSelectField,
  textField,
  urlField,
  type FieldType,
  type SelectOption,
} from "@/components/table-fields"

import { useDataTableRuntime } from "./data-table-runtime-context"
import type { CellPos, DataTableColumnMeta } from "./types"

/**
 * Keys of TData whose value type extends V. Powers col.number("age")
 * type-checking. Note this is a BIDIRECTIONAL extends check (`TData[K]
 * extends V ? (V extends TData[K] ? K : never) : never`), i.e. an exact-type
 * match rather than a one-directional "assignable to V" check — `-?` also
 * strips optionality before comparing. This is deliberate: it's what makes
 * `col.text` reject a field typed `string | undefined` (which is assignable
 * to `string` in one direction but not exact). Don't "simplify" this to a
 * plain one-directional `extends` — that would silently accept wider types.
 */
type KeysMatching<TData, V> = {
  [K in keyof TData]-?: TData[K] extends V ? (V extends TData[K] ? K : never) : never
}[keyof TData] &
  string

type ColumnOptions = {
  /** Overrides the auto-generated (capitalized-key) header label. */
  header?: string
  /** Per-column editable override; undefined falls back to the table default. */
  editable?: boolean
  /** Whether the column can be sorted. Defaults to true (false for col.button). */
  enableSorting?: boolean
  /** Whether the column can be hidden via the columns menu. Defaults to true. */
  enableHiding?: boolean
  /** Whether the column can be pinned. Defaults to true. */
  enablePinning?: boolean
  /** Whether the column can be resized. Defaults to true. */
  enableResizing?: boolean
  /** Fixed column width in pixels; undefined lets TanStack use its default. */
  size?: number
}

// camelCase accessor keys aren't word-split (e.g. "firstName" only gets its
// first letter capitalized, not turned into "First Name") — pass an explicit
// `header` for multi-word keys.
function labelFor(key: string, header?: string): string {
  if (header) return header
  return key.charAt(0).toUpperCase() + key.slice(1)
}

/**
 * Renders a field's display or edit UI depending on live DataTableRuntime
 * state. Built once per column (stable identity across renders), so it can
 * hold its own local "staged" edit value via useState — `field.edit` itself
 * is a plain function (not a component), so all editing state lives here,
 * one level up, and is handed to `field.edit` through FieldEditContext.
 */
function makeFieldCell<TData, V>(
  field: FieldType<V>,
  columnEditableOverride: boolean | undefined,
) {
  return function FieldCell(ctx: CellContext<TData, unknown>) {
    const runtime = useDataTableRuntime()
    const value = ctx.getValue() as V
    const pos: CellPos = { rowId: ctx.row.id, columnId: ctx.column.id }
    const [staged, setStaged] = React.useState<V>(value)
    // isEditing and isActive must both be computed before any hook call below
    // (Rules of Hooks forbid calling useEffect only on some render paths), so
    // they can't be read from `runtime` after the `if (!runtime)` early
    // return.
    const isEditing = runtime ? runtime.isEditing(pos) : false
    const isActive = runtime ? runtime.isActive(pos) : false
    const cellRef = React.useRef<HTMLDivElement>(null)
    // Captured in onMouseDown, read in onClick — see the comment on
    // onMouseDown below for why onClick can't just read `isActive` directly.
    const wasActiveBeforeMouseDownRef = React.useRef(false)

    React.useEffect(() => {
      if (isEditing) setStaged(value)
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isEditing])

    // Keep real DOM focus in sync with the logical active cell — arrow-key/
    // Tab navigation (useGridNavigation.moveActive) only updates React state,
    // it never calls .focus() itself. Without this, document.activeElement
    // can drift from the cell that's visually/logically active, which is a
    // real screen-reader bug even though keyboard nav still mechanically
    // works (the keydown listener sits on an ancestor and catches bubbled
    // events regardless of which descendant has focus).
    //
    // Depends on BOTH [isActive, isEditing], not just [isActive]: this cell's
    // <div ref={cellRef}> is unmounted while isEditing is true (the
    // `field.edit(...)` branch below returns a completely different tree,
    // e.g. an <input>) and remounted — a fresh DOM node, ref reattached from
    // scratch — the moment isEditing flips back to false. beginEdit/
    // stopEditing never touch activeCell, so a cell can stay active the
    // entire time isEditing goes true→false (Escape, or committing an edit);
    // with only [isActive] as the dependency, isActive never changes across
    // that cycle, so the effect wouldn't rerun and the newly-remounted div
    // would never get focused — document.activeElement would fall back to
    // <body> (whatever last had focus, e.g. the just-unmounted <input>) even
    // though the ring still shows this cell as active. That's not just a
    // cosmetic miss: with focus on <body>, the wrapper's onKeyDown (bound on
    // a div that is an ANCESTOR of body's children, not of body itself) never
    // sees the event — Enter, arrows, everything silently does nothing until
    // the user clicks again. Depending on isEditing too makes the effect
    // rerun exactly on that remount and reclaim focus. Still can't steal
    // focus from an editor mid-edit in another cell (that cell's own isActive
    // is false) and still can't loop (calling .focus() here re-triggers this
    // cell's onFocus → setActiveCell with the same pos, a same-value update:
    // isActive and isEditing both stay put, so this effect's deps don't
    // change and it doesn't refire).
    React.useEffect(() => {
      if (isActive && !isEditing) cellRef.current?.focus()
    }, [isActive, isEditing])

    if (!runtime) {
      // No <DataTable> runtime in scope — degrade to a plain read-only cell.
      return field.display(ctx as CellContext<unknown, V>)
    }

    const editable =
      (columnEditableOverride ?? runtime.isColumnEditable(pos.columnId)) && Boolean(field.edit)

    if (isEditing && field.edit) {
      return field.edit({
        value: staged,
        setValue: setStaged,
        commit: () => {
          runtime.updateData(pos.rowId, pos.columnId, staged)
          runtime.stopEditing()
        },
        cancel: () => runtime.stopEditing(),
        focusNext: (dir) => {
          // moveActive already clears editingCell internally, so an explicit
          // stopEditing() here would be redundant.
          runtime.moveActive(dir)
        },
      })
    }

    return (
      <div
        ref={cellRef}
        tabIndex={0}
        data-active={isActive ? "true" : undefined}
        // A real mouse click dispatches `mousedown` → native focus move →
        // `focus` → `mouseup` → `click`, as separate top-level browser
        // events. Each one gets its own React commit, so by the time
        // `onClick` runs, the `focus` event above has *already* called
        // `runtime.setActiveCell(pos)` and re-rendered this cell with
        // `isActive: true` — even on a cell that was NOT active before this
        // click. Reading `isActive` inside `onClick` therefore can't tell
        // "was already active" (click #2, should edit) apart from "just
        // became active via this click's own focus event" (click #1, should
        // only activate): both read `isActive === true`. Every first click on
        // an inactive editable cell would incorrectly jump straight to edit
        // mode. `onMouseDown` fires BEFORE the browser moves focus, so it's
        // the only handler that sees the true pre-click state; capture it
        // here and have onClick decide off the captured ref instead of the
        // (by-then-stale-for-this-purpose) live `isActive`.
        onMouseDown={() => {
          wasActiveBeforeMouseDownRef.current = isActive
        }}
        onClick={() => {
          if (wasActiveBeforeMouseDownRef.current && editable) runtime.beginEdit(pos)
          else runtime.setActiveCell(pos)
        }}
        onFocus={() => runtime.setActiveCell(pos)}
        className="overflow-hidden text-ellipsis whitespace-nowrap rounded-sm px-2 py-1 outline-none data-[active=true]:ring-2 data-[active=true]:ring-ring data-[active=true]:ring-inset"
      >
        {field.display(ctx as CellContext<unknown, V>)}
      </div>
    )
  }
}

function buildColumn<TData, V>(
  field: FieldType<V>,
  key: string,
  opts: ColumnOptions = {},
  buildOpts: { noAccessor?: boolean } = {},
): ColumnDef<TData, unknown> {
  // A column whose field has no `edit` renderer (e.g. col.multiSelect,
  // col.button) can never actually be edited, no matter what the table-level
  // default or an explicit opts.editable says — editing without an editor is
  // meaningless. Forcing `editable: false` here (an explicit false, not
  // undefined) makes isColumnEditable's `override ?? tableDefault`
  // resolution (use-data-table.ts) correctly return false for these columns
  // regardless of the table default, which in turn makes
  // useGridNavigation.beginEdit's existing isColumnEditable check correctly
  // refuse to enter edit mode via Enter — closing the gap at the source
  // instead of teaching beginEdit about field.edit. When field.edit IS
  // defined, this passes opts.editable through unchanged (including
  // undefined, which correctly falls back to the table default).
  const editable = field.edit ? opts.editable : false
  const meta: DataTableColumnMeta = {
    editable,
    label: labelFor(key, opts.header),
    // `V` is erased at the ColumnDef<TData, unknown> boundary this function
    // returns into — the casts here are safe because toClipboard/fromClipboard
    // are always called with values that flowed through THIS SAME column
    // (either read via row.getValue(column.id), or about to be written back
    // via updateData for that same column), never a value from a different
    // column's V.
    toClipboard: field.toClipboard as (value: unknown) => string,
    fromClipboard: field.fromClipboard as (text: string) => unknown,
  }
  return {
    id: key,
    // `key` is a validated TData key for every field method except
    // col.button (where `noAccessor` is set and this line is skipped
    // entirely — see below). `as never` sidesteps ColumnDef's accessorKey
    // overload resolution, which otherwise can't unify with the generic `V`
    // used here; `keyof TData & string` doesn't type-check because TData
    // isn't statically known to have a string-keyed shape at this call site.
    ...(buildOpts.noAccessor ? {} : { accessorKey: key as never }),
    header: meta.label,
    cell: makeFieldCell<TData, V>(field, editable),
    meta,
    enableSorting: opts.enableSorting ?? true,
    enableHiding: opts.enableHiding ?? true,
    enablePinning: opts.enablePinning ?? true,
    enableResizing: opts.enableResizing ?? true,
    size: opts.size,
  }
}

/**
 * Returns a typed `col` builder closed over TData. Each method constrains its
 * accessor key to a TData key whose value type matches the field (e.g.
 * `col.number` only accepts keys typed `number`), and returns a ColumnDef
 * ready to drop into `columns: [...]`.
 */
export function defineColumns<TData>() {
  return {
    text: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(textField(), key, opts),
    longText: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(longTextField(), key, opts),
    url: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(urlField(), key, opts),
    email: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(emailField(), key, opts),
    phone: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(phoneField(), key, opts),
    number: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { locale?: string; maximumFractionDigits?: number },
    ) => buildColumn<TData, number>(numberField(opts), key, opts),
    currency: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { currency?: string; locale?: string },
    ) => buildColumn<TData, number>(currencyField(opts), key, opts),
    percent: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { locale?: string; maximumFractionDigits?: number },
    ) => buildColumn<TData, number>(percentField(opts), key, opts),
    duration: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { unit?: "s" | "ms"; maxUnits?: number },
    ) => buildColumn<TData, number>(durationField(opts), key, opts),
    singleSelect: (
      key: KeysMatching<TData, string>,
      opts: ColumnOptions & { options: SelectOption[] },
    ) => buildColumn<TData, string>(singleSelectField(opts), key, opts),
    multiSelect: (
      key: KeysMatching<TData, string[]>,
      opts: ColumnOptions & { options: SelectOption[] },
    ) => buildColumn<TData, string[]>(multiSelectField(opts), key, opts),
    checkbox: (key: KeysMatching<TData, boolean>, opts?: ColumnOptions) =>
      buildColumn<TData, boolean>(checkboxField(), key, opts),
    rating: (key: KeysMatching<TData, number>, opts?: ColumnOptions & { max?: number }) =>
      buildColumn<TData, number>(ratingField(opts), key, opts),
    date: (
      key: KeysMatching<TData, Date | string>,
      opts?: ColumnOptions & { withTime?: boolean; locale?: string },
    ) => buildColumn<TData, Date | string>(dateField(opts), key, opts),
    button: (
      id: string,
      opts: ColumnOptions & { label: string; onClick: (row: TData) => void },
    ) =>
      // buttonField's display never reads ctx.getValue() — it's an action
      // column, not a data column — so it defaults to unsortable (still
      // overridable via an explicit opts.enableSorting) and has no real
      // TData accessor (id-only display column; see buildColumn's
      // `noAccessor`), since `id` here is just an identifier, not a key into
      // TData.
      buildColumn<TData, unknown>(
        buttonField<TData>(opts),
        id,
        { ...opts, enableSorting: opts.enableSorting ?? false },
        { noAccessor: true },
      ),
  }
}

"use client"

// base-ui build of the primitives shim. Keep the EXPORTED API identical to its
// Radix twin, primitives.radix.tsx — only the function bodies may differ. The
// divergences between the two files are exactly:
//   1. <Select> takes the base-ui-only `items` prop here; the Radix build omits it.
//   2. base-ui `onValueChange` is nullable, so FieldSelect guards `v != null`;
//      the Radix build's is `(value: string) => void` and needs no guard.
//   3. PopoverButtonTrigger composes via base-ui's `render` prop here; the Radix
//      build uses `asChild` with a nested <Button>.
// If you change a prop name, type, or default below, mirror it in the twin.

import * as React from "react"

import { Button } from "@/components/ui/button"
import { PopoverTrigger } from "@/components/ui/popover"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

export type SelectOption = { value: string; label: string }

export type FieldSelectProps = {
  value: string
  items: SelectOption[]
  onValueChange: (value: string) => void
  ariaLabel: string
  placeholder?: string
  size?: "sm" | "default"
  className?: string
}

/**
 * Single-select normalized across base-ui / Radix. The base-ui build passes the
 * required `items` prop to the Select root and guards the nullable onValueChange;
 * the Radix build (primitives.radix.tsx) omits `items`. Callers never touch the
 * primitive Select API directly, so the rest of the component is base-agnostic.
 */
export function FieldSelect({
  value,
  items,
  onValueChange,
  ariaLabel,
  placeholder,
  size = "sm",
  className,
}: FieldSelectProps) {
  return (
    <Select
      value={value}
      items={items}
      onValueChange={(v) => v != null && onValueChange(String(v))}
    >
      <SelectTrigger aria-label={ariaLabel} size={size} className={className}>
        <SelectValue placeholder={placeholder} />
      </SelectTrigger>
      <SelectContent>
        {items.map((item) => (
          <SelectItem key={item.value} value={item.value}>
            {item.label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  )
}

export type PopoverButtonTriggerProps = {
  children: React.ReactNode
  variant?: React.ComponentProps<typeof Button>["variant"]
  size?: React.ComponentProps<typeof Button>["size"]
  className?: string
  ariaLabel?: string
  disabled?: boolean
}

/**
 * Popover trigger rendered as a Button, normalized across base-ui / Radix. The
 * base-ui build uses base-ui's `render` prop; the Radix build uses `asChild`.
 * Must be used inside a <Popover>.
 */
export function PopoverButtonTrigger({
  children,
  variant = "outline",
  size = "sm",
  className,
  ariaLabel,
  disabled,
}: PopoverButtonTriggerProps) {
  return (
    <PopoverTrigger
      render={(p) => (
        <Button
          {...p}
          type="button"
          variant={variant}
          size={size}
          aria-label={ariaLabel}
          className={className}
          disabled={disabled}
        />
      )}
    >
      {children}
    </PopoverTrigger>
  )
}

"use client"

import type { CellContext, ColumnDef, HeaderContext } from "@tanstack/react-table"
import { Minus } from "lucide-react"
import * as React from "react"

import { Checkbox } from "@/components/ui/checkbox"
import { cn } from "@/lib/utils"

import { useDataTableRuntime } from "./data-table-runtime-context"

/** Stable id for the injected leading gutter column (row numbers + selection). */
export const ROW_GUTTER_COLUMN_ID = "__row-gutter__"

function SelectAllHeader<TData>({ table }: HeaderContext<TData, unknown>) {
  const runtime = useDataTableRuntime()
  const isAllMatchingSelected = runtime?.isAllMatchingSelected ?? false
  const hasMoreThanLoaded =
    (runtime?.manualPagination ?? false) &&
    (runtime?.totalRowCount ?? 0) > table.getFilteredRowModel().flatRows.length

  const allPageSelected = table.getIsAllPageRowsSelected()
  const allLoadedSelected = table.getIsAllRowsSelected()
  const someSelected = table.getIsSomeRowsSelected() || table.getIsSomePageRowsSelected()

  const checked = isAllMatchingSelected || allLoadedSelected
  const indeterminate = !checked && someSelected

  const ariaLabel = isAllMatchingSelected
    ? "All matching rows selected — deselect"
    : allLoadedSelected
      ? hasMoreThanLoaded
        ? "All loaded rows selected — deselect, or select all matching rows"
        : "Deselect all rows"
      : someSelected
        ? "Some rows selected — select all"
        : "Select all rows"

  function handleClick() {
    if (isAllMatchingSelected) {
      runtime?.setAllMatchingSelected(false)
      table.toggleAllRowsSelected(false)
      return
    }
    if (allLoadedSelected) {
      if (hasMoreThanLoaded) runtime?.setAllMatchingSelected(true)
      else table.toggleAllRowsSelected(false)
      return
    }
    if (allPageSelected) {
      table.toggleAllRowsSelected(true)
      return
    }
    table.toggleAllPageRowsSelected(true)
  }

  return (
    <div className="relative inline-flex items-center justify-center">
      <Checkbox
        checked={checked}
        indeterminate={indeterminate}
        onCheckedChange={handleClick}
        aria-label={ariaLabel}
        className={indeterminate ? "[&_svg]:opacity-0" : undefined}
      />
      {indeterminate ? (
        <Minus className="pointer-events-none absolute size-3" aria-hidden="true" />
      ) : null}
    </div>
  )
}

function RowGutterCell<TData>({ row, table }: CellContext<TData, unknown>) {
  const runtime = useDataTableRuntime()
  const selected = row.getIsSelected()
  // Captured on pointerdown (fires well before the click that triggers
  // onCheckedChange) rather than read off onCheckedChange's own event
  // payload — base-ui's `eventDetails.event` carries the native event, but
  // Radix's onCheckedChange is `(checked) => void` with no second argument
  // at all (a long-standing gap — radix-ui/primitives#734). This
  // shiftKey-capture logic is identical in row-gutter.tsx and
  // row-gutter.radix.tsx — onPointerDown is a plain DOM prop both
  // primitives forward to their underlying element unchanged; only
  // SelectAllHeader's checked/indeterminate wiring differs between the two.
  const shiftKeyRef = React.useRef(false)
  // `pagination` is an unconditional built-in TanStack feature — the state
  // key always exists (default `{pageIndex: 0, pageSize: 10}`) even when
  // `enablePagination` is false, so this is never undefined in practice.
  const { pageIndex, pageSize } = table.getState().pagination
  // `row.index` is NOT this row's position in the currently-displayed order
  // — it's fixed at row creation to the row's index in its parent array
  // (i.e. the original, unsorted `data`), and getSortedRowModel preserves it
  // via a shallow copy (`{...row}`) rather than reassigning it. Sorting a
  // column then leaves `row.index` scrambled relative to what's on screen.
  // The row's real display position is its index within the current row
  // model instead — looked up by id, not by reference: the `row` this cell
  // receives via CellContext and the entries in `table.getRowModel().rows`
  // are logically the same row but NOT the same object (getSortedRowModel
  // rebuilds a fresh `{...row}` copy per row on each recomputation), so
  // `indexOf(row)` always misses and silently returns -1.
  const displayIndex = table.getRowModel().rows.findIndex((r) => r.id === row.id)
  const rowNumber = pageIndex * pageSize + displayIndex + 1

  // Both the number and the checkbox are always mounted; only their CSS
  // visibility toggles. An earlier version tracked hover via onMouseEnter/
  // onMouseLeave React state, but the shared Checkbox primitive gives itself
  // an oversized invisible touch target (`after:-inset-x-3 after:-inset-y-2`
  // in components/ui/checkbox.tsx) for accessibility — that hit region
  // spills a few pixels past this cell's own bounds into the row above/
  // below, so the pointer can cross into a neighboring row's territory
  // without ever firing this row's mouseleave, leaving its checkbox stuck
  // visible. Driving visibility from real-time `:hover`/`:focus-within`
  // instead of discrete enter/leave events sidesteps that entirely — CSS
  // pseudo-classes re-evaluate continuously from actual cursor/focus
  // position, so there's nothing to get "stuck". `[tr:hover_&]` (already
  // used the same way for pinned-column highlighting in data-table.tsx)
  // reveals on hovering anywhere in the row, not just this narrow cell,
  // matching the row's own native hover background. `group`/
  // `group-focus-within` keep it keyboard-reachable: tabbing onto this
  // cell's div reveals the checkbox so a second Tab can land on it.
  const numberHiddenClass = selected ? "hidden" : "[tr:hover_&]:hidden group-focus-within:hidden"
  const checkboxWrapperClass = selected
    ? "inline-flex"
    : "hidden [tr:hover_&]:inline-flex group-focus-within:inline-flex"

  return (
    <div
      className="group flex h-full items-center justify-center px-2 py-1 text-xs text-muted-foreground"
      tabIndex={0}
      aria-label={selected ? undefined : `Row ${rowNumber}`}
    >
      <span className={cn("tabular-nums", numberHiddenClass)}>{rowNumber}</span>
      <span className={checkboxWrapperClass}>
        <Checkbox
          checked={selected}
          onPointerDown={(e) => {
            shiftKeyRef.current = e.shiftKey
          }}
          onKeyDown={(e) => {
            // Space/Enter-triggered toggles (keyboard activation) never fire
            // pointerdown, so track the modifier here too — otherwise
            // shiftKeyRef could still hold a stale value from an earlier
            // mouse click.
            shiftKeyRef.current = e.shiftKey
          }}
          onCheckedChange={(checked) => {
            runtime?.toggleRowSelected(row.id, checked === true, shiftKeyRef.current)
          }}
          aria-label={selected ? `Deselect row ${rowNumber}` : `Select row ${rowNumber}`}
        />
      </span>
    </div>
  )
}

/**
 * Builds the leading gutter column: row numbers that swap to a selection
 * checkbox on hover (or when the row is selected), plus a tri-state
 * select-all checkbox in the header. Prepended to the user's columns by
 * useDataTable (Task 3) when `enableRowSelection` is true — not part of the
 * `defineColumns` builder, since it's a structural, table-owned column with
 * no TData accessor.
 */
export function buildRowGutterColumn<TData>(): ColumnDef<TData, unknown> {
  return {
    id: ROW_GUTTER_COLUMN_ID,
    header: SelectAllHeader,
    cell: RowGutterCell,
    enableSorting: false,
    enableHiding: false,
    enablePinning: false,
    enableResizing: false,
    size: 40,
  }
}

"use client"

import type { Column } from "@tanstack/react-table"
import { ArrowDown, ArrowUp, ChevronsUpDown } from "lucide-react"
import type * as React from "react"

export function ColumnHeader<TData>({
  column,
  label,
  icon: Icon,
}: {
  column: Column<TData>
  label: React.ReactNode
  icon?: React.ComponentType<{ className?: string }>
}) {
  const canSort = column.getCanSort()

  if (!canSort) {
    return (
      <span className="flex items-center gap-1.5 text-muted-foreground">
        {Icon ? (
          <span aria-hidden="true">
            <Icon className="size-4" />
          </span>
        ) : null}
        {label}
      </span>
    )
  }

  const sorted = column.getIsSorted()
  const sortState =
    sorted === "asc" ? "sorted ascending" : sorted === "desc" ? "sorted descending" : "not sorted"
  const ariaLabel = typeof label === "string" ? `${label}, ${sortState}` : sortState

  return (
    <button
      type="button"
      onClick={column.getToggleSortingHandler()}
      aria-label={ariaLabel}
      className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground"
    >
      {Icon ? (
        <span aria-hidden="true">
          <Icon className="size-4" />
        </span>
      ) : null}
      {label}
      {sorted === "asc" ? (
        <ArrowUp data-sort="asc" className="size-4" aria-hidden="true" />
      ) : sorted === "desc" ? (
        <ArrowDown data-sort="desc" className="size-4" aria-hidden="true" />
      ) : (
        <ChevronsUpDown data-sort="none" className="size-4 opacity-40" aria-hidden="true" />
      )}
    </button>
  )
}

"use client"

import type { Table } from "@tanstack/react-table"
import { ArrowLeftToLine, ArrowRightToLine, Columns3 } from "lucide-react"

import { Button } from "@/components/ui/button"
import { Checkbox } from "@/components/ui/checkbox"
import { Popover, PopoverContent } from "@/components/ui/popover"

import { PopoverButtonTrigger } from "./primitives"
import type { DataTableColumnMeta } from "./types"

export function ColumnsMenuContent<TData>({ table }: { table: Table<TData> }) {
  // Columns that can neither be hidden nor pinned (e.g. row-gutter.tsx's
  // structural selection/row-number column, which sets both to false) have
  // nothing for this menu to offer — every control below is conditional on
  // one of those two capabilities, so such a column would otherwise render
  // as a bare row showing its raw internal id with no controls at all.
  const columns = table.getAllLeafColumns().filter((column) => column.getCanHide() || column.getCanPin())

  return (
    <div className="space-y-0.5">
      {columns.map((column) => {
        const label = (column.columnDef.meta as DataTableColumnMeta | undefined)?.label ?? column.id
        const pinned = column.getIsPinned()
        return (
          <div
            key={column.id}
            className="flex items-center justify-between gap-2 rounded-sm px-1 py-1 text-sm hover:bg-muted"
          >
            <label className="flex flex-1 cursor-pointer items-center gap-2 select-none">
              {column.getCanHide() ? (
                <Checkbox
                  checked={column.getIsVisible()}
                  onCheckedChange={(checked) => column.toggleVisibility(checked === true)}
                />
              ) : null}
              <span className="flex-1">{label}</span>
            </label>
            {column.getCanPin() ? (
              <div className="flex items-center gap-0.5">
                <Button
                  type="button"
                  variant={pinned === "left" ? "secondary" : "ghost"}
                  size="icon-xs"
                  aria-label={`Pin ${label} left`}
                  onClick={() => column.pin(pinned === "left" ? false : "left")}
                >
                  <ArrowLeftToLine className="size-3.5" aria-hidden="true" />
                </Button>
                <Button
                  type="button"
                  variant={pinned === "right" ? "secondary" : "ghost"}
                  size="icon-xs"
                  aria-label={`Pin ${label} right`}
                  onClick={() => column.pin(pinned === "right" ? false : "right")}
                >
                  <ArrowRightToLine className="size-3.5" aria-hidden="true" />
                </Button>
              </div>
            ) : null}
          </div>
        )
      })}
    </div>
  )
}

export function ColumnsMenu<TData>({ table }: { table: Table<TData> }) {
  return (
    <Popover>
      <PopoverButtonTrigger className="gap-2">
        <Columns3 className="size-4" aria-hidden="true" />
        Columns
      </PopoverButtonTrigger>
      <PopoverContent align="start" className="w-64">
        <ColumnsMenuContent table={table} />
      </PopoverContent>
    </Popover>
  )
}

"use client"

import { ChevronDown } from "lucide-react"

import { cn } from "@/lib/utils"
import { Checkbox } from "@/components/ui/checkbox"
import { Popover, PopoverContent } from "@/components/ui/popover"

import { PopoverButtonTrigger } from "./primitives"

export type MultiSelectOption = { label: string; value: string }

type MultiSelectProps = {
  options: MultiSelectOption[]
  selected: string[]
  onChange: (next: string[]) => void
  placeholder?: string
  /**
   * Accessible label for the trigger button. Pass this whenever the visible
   * label ("N selected") doesn't convey what is being selected (the common case).
   */
  ariaLabel?: string
  className?: string
}

export function multiSelectLabel(selected: string[], placeholder: string): string {
  return selected.length === 0 ? placeholder : `${selected.length} selected`
}

export function MultiSelectContent({
  options,
  selected,
  onChange,
}: Pick<MultiSelectProps, "options" | "selected" | "onChange">) {
  // Controlled: each checkbox reflects `selected`, so duplicate-adds can't occur
  // as long as the caller feeds the updated `selected` back before the next click.
  function toggle(value: string, checked: boolean) {
    onChange(checked ? [...selected, value] : selected.filter((v) => v !== value))
  }
  return (
    <div className="flex max-h-64 flex-col gap-1 overflow-auto">
      {options.map((opt) => (
        <label
          key={opt.value}
          className="flex cursor-pointer items-center gap-2 rounded-sm px-1 py-1 text-sm select-none hover:bg-muted"
        >
          <Checkbox
            checked={selected.includes(opt.value)}
            onCheckedChange={(checked) => toggle(opt.value, checked === true)}
          />
          {opt.label}
        </label>
      ))}
    </div>
  )
}

export function MultiSelect({
  options,
  selected,
  onChange,
  placeholder = "Select…",
  ariaLabel,
  className,
}: MultiSelectProps) {
  return (
    <Popover>
      <PopoverButtonTrigger
        ariaLabel={ariaLabel}
        className={cn("h-8 justify-between gap-2 font-normal", className)}
      >
        <span className={cn(selected.length === 0 && "text-muted-foreground")}>
          {multiSelectLabel(selected, placeholder)}
        </span>
        <ChevronDown className="size-3 shrink-0 opacity-60" aria-hidden="true" />
      </PopoverButtonTrigger>
      <PopoverContent align="start" className="w-56">
        <MultiSelectContent options={options} selected={selected} onChange={onChange} />
      </PopoverContent>
    </Popover>
  )
}

